<?php
namespace App\Actions\Invoices;
use App\Models\{Invoice,User}; use Illuminate\Support\Facades\DB;
class CreateInvoice { public function handle(User $user, array $data): Invoice { return DB::transaction(function () use ($user, $data) { $business=$user->currentBusiness; $next=Invoice::where('business_id',$business->id)->count()+1; $subtotal=0; $taxTotal=0; foreach ($data['items'] as $item) { $line=(float)$item['quantity']*(float)$item['unit_price']; $tax=$line*((float)($item['tax_rate'] ?? $business->vat_rate)/100); $subtotal += $line; $taxTotal += $tax; } $invoice=Invoice::create(['business_id'=>$business->id,'customer_id'=>$data['customer_id'],'invoice_number'=>'INV-'.str_pad((string)$next,5,'0',STR_PAD_LEFT),'issue_date'=>$data['issue_date'],'due_date'=>$data['due_date'],'status'=>'draft','subtotal'=>$subtotal,'tax_total'=>$taxTotal,'total'=>$subtotal+$taxTotal,'amount_paid'=>0,'notes'=>$data['notes'] ?? null]); foreach ($data['items'] as $item) { $line=(float)$item['quantity']*(float)$item['unit_price']; $rate=(float)($item['tax_rate'] ?? $business->vat_rate); $invoice->items()->create(['description'=>$item['description'],'quantity'=>$item['quantity'],'unit_price'=>$item['unit_price'],'tax_rate'=>$rate,'line_total'=>$line + ($line*$rate/100)]); } return $invoice; }); } }
